import { CommonModule } from "@angular/common";
import { Component, HostListener, OnInit, inject } from "@angular/core";
import { FormsModule } from "@angular/forms";
import { ActivatedRoute, Router, RouterLink } from "@angular/router";
import { forkJoin } from "rxjs";
import { LecturerService } from "../../services/lecturer.service";

type ContentItemType = "VIDEO" | "MATERIAL";
type AddMode = "VIDEO" | "MATERIAL";
type SettingsSection = "COURSE_CONTENT" | "LEARNING_RESOURCES" | "UPDATING_VIDEO";
type ManageTab = "CREATE" | "EDIT" | "CONTENT";
type AssessmentToolTab = "COURSE" | "QUIZ" | "QUESTION" | "BANK" | "PERFORMANCE";

type ContentItem = {
  itemType: ContentItemType;
  id: number;
  title: string;
  description?: string;
  videoUrl?: string;
  durationMinutes?: number;
  sortOrder?: number;
  mandatory?: boolean;
  materialType?: string;
  resourceUrl?: string;
};

@Component({
  selector: "app-lecturer-manage",
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: "./lecturer-manage.component.html",
  styleUrl: "./lecturer-manage.component.css"
})
export class LecturerManageComponent implements OnInit {
  private readonly lecturerService = inject(LecturerService);
  private readonly route = inject(ActivatedRoute);
  private readonly router = inject(Router);

  courses: any[] = [];
  quizzes: any[] = [];
  contentItems: ContentItem[] = [];

  selectedCourseId: number | null = null;
  selectedContentItem: ContentItem | null = null;
  actionMenuKey: string | null = null;
  addMode: AddMode = "VIDEO";
  manageTab: ManageTab = "CREATE";
  assessmentToolTab: AssessmentToolTab = "COURSE";
  readonly settingsSections: Array<{ key: SettingsSection; label: string }> = [
    { key: "COURSE_CONTENT", label: "Course Content" },
    { key: "LEARNING_RESOURCES", label: "Learning Resources" },
    { key: "UPDATING_VIDEO", label: "Updating Video" }
  ];
  settingsSectionOpen: Record<SettingsSection, boolean> = {
    COURSE_CONTENT: true,
    LEARNING_RESOURCES: false,
    UPDATING_VIDEO: false
  };

  statusMessage = "";
  errorMessage = "";

  courseForm = {
    title: "",
    description: ""
  };

  courseEditForm = {
    title: "",
    description: ""
  };

  videoForm = {
    title: "",
    description: "",
    videoUrl: "",
    durationMinutes: 10,
    sortOrder: 1,
    mandatory: true
  };

  materialForm = {
    title: "",
    materialType: "PDF",
    resourceUrl: ""
  };

  editVideoForm = {
    title: "",
    description: "",
    videoUrl: "",
    durationMinutes: 10,
    sortOrder: 1,
    mandatory: true
  };

  editMaterialForm = {
    title: "",
    materialType: "PDF",
    resourceUrl: ""
  };

  ngOnInit(): void {
    this.route.queryParamMap.subscribe((params) => {
      const requestedCourseId = Number(params.get("courseId"));
      this.selectedCourseId = Number.isFinite(requestedCourseId) && requestedCourseId > 0
        ? requestedCourseId
        : this.selectedCourseId;

      const requestedMode = (params.get("mode") ?? "").toLowerCase();
      if (requestedMode === "create" || requestedMode === "edit" || requestedMode === "quiz") {
        this.assessmentToolTab = "QUIZ";
      } else if (requestedMode === "question" || requestedMode === "questions") {
        this.assessmentToolTab = "QUESTION";
      } else if (requestedMode === "bank") {
        this.assessmentToolTab = "BANK";
      } else if (requestedMode === "performance") {
        this.assessmentToolTab = "PERFORMANCE";
      } else {
        this.assessmentToolTab = "COURSE";
      }

      const flash = String(params.get("flash") ?? "").trim();
      if (flash) {
        this.statusMessage = flash;
      }
      this.loadCourses();
    });
  }

  @HostListener("document:click")
  closeActionMenuOnOutsideClick(): void {
    this.actionMenuKey = null;
  }

  get currentCourse(): any | null {
    return this.courses.find((course) => course.courseId === this.selectedCourseId) ?? null;
  }

  get videoItems(): ContentItem[] {
    return this.contentItems
      .filter((item) => item.itemType === "VIDEO")
      .sort((a, b) => Number(a.sortOrder ?? 0) - Number(b.sortOrder ?? 0));
  }

  get orderedContentItems(): ContentItem[] {
    const videos = this.videoItems;
    const materials = this.contentItems
      .filter((item) => item.itemType === "MATERIAL")
      .sort((a, b) => Number(a.id ?? 0) - Number(b.id ?? 0));
    return [...videos, ...materials];
  }

  loadCourses(): void {
    this.lecturerService.courses().subscribe({
      next: (courses) => {
        const previouslySelected = this.selectedCourseId;
        this.courses = courses;
        const stillExists = courses.some((course) => course.courseId === previouslySelected);
        if (stillExists) {
          this.selectedCourseId = previouslySelected;
        } else if (courses.length > 0) {
          this.selectedCourseId = courses[0].courseId;
        } else {
          this.selectedCourseId = null;
        }
        if (!this.selectedCourseId) {
          this.manageTab = "CREATE";
        } else if (this.manageTab === "CREATE") {
          this.manageTab = "EDIT";
        }
        this.syncCourseEditor();
        this.loadQuizzes();
        this.loadCourseContent();
      },
      error: (error) => this.errorMessage = error?.error?.message ?? "Failed to load courses"
    });
  }

  loadQuizzes(): void {
    this.lecturerService.quizzes(this.selectedCourseId ?? undefined).subscribe({
      next: (quizzes) => this.quizzes = quizzes,
      error: (error) => this.errorMessage = error?.error?.message ?? "Failed to load quizzes"
    });
  }

  loadCourseContent(): void {
    if (!this.selectedCourseId) {
      this.contentItems = [];
      this.selectedContentItem = null;
      return;
    }

    this.lecturerService.courseContent(this.selectedCourseId).subscribe({
      next: (data) => {
        const videos: ContentItem[] = (data?.videos ?? []).map((item: any) => ({
          ...item,
          itemType: "VIDEO"
        }));
        const materials: ContentItem[] = (data?.materials ?? []).map((item: any) => ({
          ...item,
          itemType: "MATERIAL"
        }));
        videos.sort((a, b) => Number(a.sortOrder ?? 0) - Number(b.sortOrder ?? 0));
        this.contentItems = [...videos, ...materials];
        if (!this.videoForm.title.trim() && !this.videoForm.videoUrl.trim()) {
          this.videoForm.sortOrder = this.nextVideoSortOrder();
        }
        this.restoreSelection();
      },
      error: (error) => this.errorMessage = error?.error?.message ?? "Failed to load course content"
    });
  }

  onCourseChange(raw: string): void {
    this.selectedCourseId = raw ? Number(raw) : null;
    this.selectedContentItem = null;
    this.actionMenuKey = null;
    this.manageTab = this.selectedCourseId ? "EDIT" : "CREATE";
    this.syncCourseEditor();
    this.loadQuizzes();
    this.loadCourseContent();
  }

  openCourseWorkspace(courseId: number): void {
    this.selectedCourseId = courseId;
    this.selectedContentItem = null;
    this.actionMenuKey = null;
    this.manageTab = "CONTENT";
    this.syncCourseEditor();
    this.loadQuizzes();
    this.loadCourseContent();
  }

  setManageTab(tab: ManageTab): void {
    this.manageTab = tab;
    if (tab === "CONTENT") {
      this.jumpToSection("content");
      return;
    }
    this.jumpToSection("course");
  }

  selectAssessmentTool(tab: AssessmentToolTab): void {
    this.assessmentToolTab = tab;
    const courseId = this.selectedCourseId ?? null;
    const courseTitle = this.currentCourse?.title ?? null;

    if (tab === "COURSE") {
      this.router.navigate(["/lecturer/manage"], {
        queryParams: { courseId }
      });
      return;
    }

    if (tab === "QUIZ") {
      this.router.navigate(["/lecturer/quiz-settings"], {
        queryParams: { courseId, mode: "create" }
      });
      return;
    }

    if (tab === "QUESTION") {
      this.router.navigate(["/lecturer/quiz-builder"], {
        queryParams: { courseId, mode: "questions" }
      });
      return;
    }

    if (tab === "BANK") {
      this.router.navigate(["/lecturer/question-bank"], {
        queryParams: { courseId, mode: "bank" }
      });
      return;
    }

    this.router.navigate(["/lecturer/monitoring"], {
      queryParams: { courseId, courseTitle, mode: "performance" }
    });
  }

  jumpToSection(section: "course" | "content"): void {
    const targetId = section === "course" ? "course-editor-anchor" : "content-editor-anchor";
    const target = document.getElementById(targetId);
    target?.scrollIntoView({ behavior: "smooth", block: "start" });
  }

  createCourse(): void {
    this.clearMessages();
    this.lecturerService.createCourse(this.courseForm).subscribe({
      next: (response) => {
        this.statusMessage = "Course created.";
        if (response?.courseId) {
          this.selectedCourseId = Number(response.courseId);
        }
        this.manageTab = "EDIT";
        this.courseForm = { title: "", description: "" };
        this.loadCourses();
      },
      error: (error) => this.errorMessage = error?.error?.message ?? "Failed to create course"
    });
  }

  updateSelectedCourse(): void {
    this.clearMessages();
    if (!this.selectedCourseId) {
      this.errorMessage = "Select a course first.";
      return;
    }
    this.lecturerService.updateCourse(this.selectedCourseId, this.courseEditForm).subscribe({
      next: () => {
        this.statusMessage = "Course settings updated.";
        this.loadCourses();
      },
      error: (error) => this.errorMessage = error?.error?.message ?? "Failed to update course"
    });
  }

  deleteCourse(courseId: number): void {
    this.clearMessages();
    if (!confirm("Delete this course and all related content?")) {
      return;
    }
    this.lecturerService.deleteCourse(courseId).subscribe({
      next: () => {
        this.statusMessage = "Course deleted.";
        if (this.selectedCourseId === courseId) {
          this.selectedCourseId = null;
          this.selectedContentItem = null;
          this.contentItems = [];
        }
        this.loadCourses();
      },
      error: (error) => this.errorMessage = error?.error?.message ?? "Failed to delete course"
    });
  }

  deleteSelectedCourse(): void {
    if (!this.selectedCourseId) {
      this.errorMessage = "Select a course first.";
      return;
    }
    this.deleteCourse(this.selectedCourseId);
  }

  setAddMode(mode: AddMode): void {
    this.addMode = mode;
    this.actionMenuKey = null;
  }

  toggleSettingsSection(section: SettingsSection): void {
    this.settingsSectionOpen[section] = !this.settingsSectionOpen[section];
  }

  isSettingsSectionOpen(section: SettingsSection): boolean {
    return Boolean(this.settingsSectionOpen[section]);
  }

  addVideo(): void {
    this.clearMessages();
    if (!this.selectedCourseId) {
      this.errorMessage = "Select a course first.";
      return;
    }
    this.lecturerService.addVideo(this.selectedCourseId, this.videoForm).subscribe({
      next: () => {
        this.statusMessage = "Video added.";
        this.manageTab = "CONTENT";
        this.videoForm = {
          title: "",
          description: "",
          videoUrl: "",
          durationMinutes: 10,
          sortOrder: this.nextVideoSortOrder(),
          mandatory: true
        };
        this.loadCourseContent();
        this.loadCourses();
      },
      error: (error) => this.errorMessage = error?.error?.message ?? "Failed to add video"
    });
  }

  addMaterial(): void {
    this.clearMessages();
    if (!this.selectedCourseId) {
      this.errorMessage = "Select a course first.";
      return;
    }
    this.lecturerService.addMaterial(this.selectedCourseId, this.materialForm).subscribe({
      next: () => {
        this.statusMessage = "Material added.";
        this.manageTab = "CONTENT";
        this.materialForm = {
          title: "",
          materialType: "PDF",
          resourceUrl: ""
        };
        this.loadCourseContent();
      },
      error: (error) => this.errorMessage = error?.error?.message ?? "Failed to add material"
    });
  }

  contentKey(item: ContentItem): string {
    return `${item.itemType}-${item.id}`;
  }

  toggleActions(item: ContentItem, event: Event): void {
    event.stopPropagation();
    const key = this.contentKey(item);
    this.actionMenuKey = this.actionMenuKey === key ? null : key;
  }

  selectContentItem(item: ContentItem): void {
    this.actionMenuKey = null;
    this.selectedContentItem = item;
    this.settingsSectionOpen = {
      COURSE_CONTENT: true,
      LEARNING_RESOURCES: false,
      UPDATING_VIDEO: item.itemType === "VIDEO"
    };
    if (item.itemType === "VIDEO") {
      this.editVideoForm = {
        title: item.title,
        description: item.description ?? "",
        videoUrl: item.videoUrl ?? "",
        durationMinutes: Number(item.durationMinutes ?? 10),
        sortOrder: Number(item.sortOrder ?? 1),
        mandatory: Boolean(item.mandatory)
      };
      return;
    }
    this.editMaterialForm = {
      title: item.title,
      materialType: item.materialType ?? "PDF",
      resourceUrl: item.resourceUrl ?? ""
    };
  }

  duplicateItem(item: ContentItem): void {
    this.clearMessages();
    this.actionMenuKey = null;
    const callback = item.itemType === "VIDEO"
      ? this.lecturerService.duplicateVideo(item.id)
      : this.lecturerService.duplicateMaterial(item.id);
    callback.subscribe({
      next: () => {
        this.statusMessage = `${item.itemType === "VIDEO" ? "Video" : "Material"} duplicated.`;
        this.loadCourseContent();
        this.loadCourses();
      },
      error: (error) => this.errorMessage = error?.error?.message ?? "Failed to duplicate content"
    });
  }

  canMoveVideo(item: ContentItem, direction: -1 | 1): boolean {
    if (item.itemType !== "VIDEO") {
      return false;
    }
    const videos = this.videoItems;
    const index = videos.findIndex((video) => video.id === item.id);
    if (index < 0) {
      return false;
    }
    const targetIndex = index + direction;
    return targetIndex >= 0 && targetIndex < videos.length;
  }

  moveVideo(item: ContentItem, direction: -1 | 1): void {
    if (!this.canMoveVideo(item, direction)) {
      return;
    }

    this.clearMessages();
    this.actionMenuKey = null;

    const videos = this.videoItems;
    const index = videos.findIndex((video) => video.id === item.id);
    const targetIndex = index + direction;
    const source = videos[index];
    const target = videos[targetIndex];

    const sourceSort = Number(source.sortOrder ?? index + 1);
    const targetSort = Number(target.sortOrder ?? targetIndex + 1);

    forkJoin([
      this.lecturerService.updateVideo(source.id, this.videoPayloadFromItem(source, targetSort)),
      this.lecturerService.updateVideo(target.id, this.videoPayloadFromItem(target, sourceSort))
    ]).subscribe({
      next: () => {
        this.statusMessage = "Video order updated.";
        this.loadCourseContent();
      },
      error: (error) => this.errorMessage = error?.error?.message ?? "Failed to reorder video"
    });
  }

  deleteItem(item: ContentItem): void {
    this.clearMessages();
    this.actionMenuKey = null;
    if (!confirm(`Delete "${item.title}"?`)) {
      return;
    }
    const callback = item.itemType === "VIDEO"
      ? this.lecturerService.deleteVideo(item.id)
      : this.lecturerService.deleteMaterial(item.id);
    callback.subscribe({
      next: () => {
        this.statusMessage = `${item.itemType === "VIDEO" ? "Video" : "Material"} deleted.`;
        if (this.selectedContentItem && this.contentKey(this.selectedContentItem) === this.contentKey(item)) {
          this.selectedContentItem = null;
        }
        this.loadCourseContent();
        this.loadCourses();
      },
      error: (error) => this.errorMessage = error?.error?.message ?? "Failed to delete content"
    });
  }

  saveSelectedItem(): void {
    this.clearMessages();
    if (!this.selectedContentItem) {
      return;
    }

    const item = this.selectedContentItem;
    const callback = item.itemType === "VIDEO"
      ? this.lecturerService.updateVideo(item.id, {
        title: this.editVideoForm.title.trim(),
        description: this.editVideoForm.description.trim(),
        videoUrl: this.editVideoForm.videoUrl.trim(),
        durationMinutes: Math.max(1, Number(this.editVideoForm.durationMinutes)),
        sortOrder: Math.max(1, Number(this.editVideoForm.sortOrder)),
        mandatory: Boolean(this.editVideoForm.mandatory)
      })
      : this.lecturerService.updateMaterial(item.id, {
        title: this.editMaterialForm.title.trim(),
        materialType: this.editMaterialForm.materialType.trim(),
        resourceUrl: this.editMaterialForm.resourceUrl.trim()
      });

    callback.subscribe({
      next: () => {
        this.statusMessage = `${item.itemType === "VIDEO" ? "Video" : "Material"} updated.`;
        this.loadCourseContent();
      },
      error: (error) => this.errorMessage = error?.error?.message ?? "Failed to update content"
    });
  }

  openLink(url: string | undefined): void {
    if (!url) {
      return;
    }
    window.open(url, "_blank", "noopener");
  }

  itemSubtitle(item: ContentItem): string {
    if (item.itemType === "VIDEO") {
      const duration = Number(item.durationMinutes ?? 0);
      const sort = Number(item.sortOrder ?? 0);
      const mandatory = item.mandatory ? "Mandatory" : "Optional";
      return `${duration} min | Order ${sort} | ${mandatory}`;
    }

    const typeLabel = item.materialType ?? "Material";
    return `${typeLabel} resource`;
  }

  isSelectedItem(item: ContentItem): boolean {
    if (!this.selectedContentItem) {
      return false;
    }
    return this.contentKey(item) === this.contentKey(this.selectedContentItem);
  }

  private restoreSelection(): void {
    if (!this.selectedContentItem && this.contentItems.length > 0) {
      this.selectContentItem(this.contentItems[0]);
      return;
    }

    if (!this.selectedContentItem) {
      return;
    }

    const key = this.contentKey(this.selectedContentItem);
    const found = this.contentItems.find((item) => this.contentKey(item) === key);
    if (!found) {
      if (this.contentItems.length > 0) {
        this.selectContentItem(this.contentItems[0]);
      } else {
        this.selectedContentItem = null;
      }
      return;
    }
    this.selectContentItem(found);
  }

  private syncCourseEditor(): void {
    if (!this.currentCourse) {
      this.courseEditForm = {
        title: "",
        description: ""
      };
      return;
    }

    this.courseEditForm = {
      title: this.currentCourse.title,
      description: this.currentCourse.description
    };
  }

  private nextVideoSortOrder(): number {
    const videos = this.videoItems;
    if (videos.length === 0) {
      return 1;
    }
    const highest = Math.max(...videos.map((item) => Number(item.sortOrder ?? 0)));
    return Math.max(1, highest + 1);
  }

  private videoPayloadFromItem(item: ContentItem, sortOrder: number): any {
    return {
      title: (item.title ?? "").trim() || "Video Lesson",
      description: (item.description ?? "").trim() || "Video lesson content",
      videoUrl: (item.videoUrl ?? "").trim(),
      durationMinutes: Math.max(1, Number(item.durationMinutes ?? 1)),
      sortOrder: Math.max(1, Number(sortOrder)),
      mandatory: Boolean(item.mandatory)
    };
  }

  private clearMessages(): void {
    this.statusMessage = "";
    this.errorMessage = "";
  }
}
<div class="container manage-page">
  @if (currentCourse) {
    <section class="panel quiz-mini-list">
      <div class="assessment-tabs" role="tablist" aria-label="Assessment Tools">
        <button
          class="assessment-tab"
          role="tab"
          type="button"
          [class.active]="assessmentToolTab === 'COURSE'"
          [attr.aria-selected]="assessmentToolTab === 'COURSE'"
          (click)="selectAssessmentTool('COURSE')">
          My Course
        </button>
        <button
          class="assessment-tab"
          role="tab"
          type="button"
          [class.active]="assessmentToolTab === 'QUIZ'"
          [attr.aria-selected]="assessmentToolTab === 'QUIZ'"
          (click)="selectAssessmentTool('QUIZ')">
          Quiz
        </button>
        <button
          class="assessment-tab"
          role="tab"
          type="button"
          [class.active]="assessmentToolTab === 'QUESTION'"
          [attr.aria-selected]="assessmentToolTab === 'QUESTION'"
          (click)="selectAssessmentTool('QUESTION')">
          Question
        </button>
        <button
          class="assessment-tab"
          role="tab"
          type="button"
          [class.active]="assessmentToolTab === 'BANK'"
          [attr.aria-selected]="assessmentToolTab === 'BANK'"
          (click)="selectAssessmentTool('BANK')">
          Question Bank
        </button>
        <button
          class="assessment-tab"
          role="tab"
          type="button"
          [class.active]="assessmentToolTab === 'PERFORMANCE'"
          [attr.aria-selected]="assessmentToolTab === 'PERFORMANCE'"
          (click)="selectAssessmentTool('PERFORMANCE')">
          Performance
        </button>
      </div>
    </section>
  }

  @if (statusMessage) {
    <p class="ok">{{ statusMessage }}</p>
  }
  @if (errorMessage) {
    <p class="error">{{ errorMessage }}</p>
  }

  <section class="panel manage-unified-card">
    <header class="manage-header">
      <div>
        <h1>{{ currentCourse?.title || "Course Content Management" }}</h1>
        <p class="muted">
          {{ currentCourse ? ("Manage lessons, resources, and quiz flow for " + currentCourse.title + ".") : "Manage lessons and resources with a clear content workflow." }}
        </p>
      </div>
    </header>

    <section class="workflow-panel">
      <h2>Course Management Flow</h2>
      <p class="muted">
        Follow this order: create course first, then edit course details, then manage course content and update lesson video.
      </p>
      <div class="flow-tabs">
        <button class="flow-tab" type="button" [class.active]="manageTab === 'CREATE'" (click)="setManageTab('CREATE')">
          1. Create New Course
        </button>
        <button
          class="flow-tab"
          type="button"
          [class.active]="manageTab === 'EDIT'"
          [disabled]="!currentCourse"
          (click)="setManageTab('EDIT')">
          2. Edit Course
        </button>
        <button
          class="flow-tab"
          type="button"
          [class.active]="manageTab === 'CONTENT'"
          [disabled]="!currentCourse"
          (click)="setManageTab('CONTENT')">
          3. Course Content &amp; Updating Lesson Video
        </button>
      </div>
    </section>

    <section class="toolbar-panel" id="course-editor-anchor">
      @if (manageTab !== "CREATE") {
        <div class="toolbar-top">
          <div class="field course-select-field">
            <label for="courseSelect">Select Course</label>
            <select id="courseSelect" [ngModel]="selectedCourseId ?? ''" (ngModelChange)="onCourseChange($event)" name="courseSelect">
              <option value="">-- Select Course --</option>
              @for (course of courses; track course.courseId) {
                <option [value]="course.courseId">{{ course.title }}</option>
              }
            </select>
          </div>
        </div>
      }

      @if (manageTab === "CREATE") {
        <form class="create-course-form" (ngSubmit)="createCourse()">
          <div class="field">
            <label for="newCourseTitle">New Course Title</label>
            <input id="newCourseTitle" name="newCourseTitle" placeholder="e.g. Data Management and Integration" [(ngModel)]="courseForm.title" required>
          </div>
          <div class="field">
            <label for="newCourseDescription">Description</label>
            <input id="newCourseDescription" name="newCourseDescription" placeholder="Brief course description" [(ngModel)]="courseForm.description" required>
          </div>
          <div class="form-actions">
            <button class="btn" type="submit">Create Course</button>
          </div>
        </form>
      }

      @if (manageTab === "EDIT") {
        @if (currentCourse) {
          <form class="course-edit-form" (ngSubmit)="updateSelectedCourse()">
            <div class="field">
              <label for="courseTitle">Course Title</label>
              <input id="courseTitle" name="courseTitle" [(ngModel)]="courseEditForm.title" required>
            </div>
            <div class="field">
              <label for="courseDescription">Course Description</label>
              <input id="courseDescription" name="courseDescription" [(ngModel)]="courseEditForm.description" required>
            </div>
            <div class="form-actions">
              <button class="btn" type="submit">Update Course</button>
              <button class="btn btn-danger" type="button" (click)="deleteSelectedCourse()">Delete Course</button>
            </div>
          </form>
        } @else {
          <p class="warning">Select a course first before editing.</p>
        }
      }

      @if (manageTab === "CONTENT") {
        @if (currentCourse) {
          <div class="content-entry-note">
            <h3>{{ currentCourse.title }} - Course Content Workspace</h3>
            <p class="muted">Now you can add/update video, material, and edit lesson settings below.</p>
            <button class="btn btn-outline" type="button" (click)="jumpToSection('content')">Open Content Section</button>
          </div>
        } @else {
          <p class="warning">Select a course first before managing course content.</p>
        }
      }
    </section>
  </section>

  @if (manageTab === "CONTENT") {
    <section class="workspace-grid" id="content-editor-anchor">
      <aside class="panel content-panel">
      <header class="content-panel-head">
        <h2>Course Content</h2>
        <p class="muted">Add and organize lesson videos and learning materials.</p>
      </header>

      @if (!selectedCourseId) {
        <p class="warning">Select a course first before adding content.</p>
      } @else {
        <div class="add-toggle">
          <button class="btn" type="button" [class.btn-outline]="addMode !== 'VIDEO'" (click)="setAddMode('VIDEO')">
            Add Video
          </button>
          <button class="btn" type="button" [class.btn-outline]="addMode !== 'MATERIAL'" (click)="setAddMode('MATERIAL')">
            Add Material
          </button>
        </div>

        @if (addMode === "VIDEO") {
          <form class="content-form compact-form-card" (ngSubmit)="addVideo()">
            <div class="field">
              <label for="videoTitle">Video Title</label>
              <input id="videoTitle" name="videoTitle" placeholder="A lesson about dogs" [(ngModel)]="videoForm.title" required>
            </div>

            <div class="field">
              <label for="videoDescription">Description</label>
              <textarea id="videoDescription" name="videoDescription" rows="3" [(ngModel)]="videoForm.description" required></textarea>
            </div>

            <div class="field">
              <label for="videoUrl">Video URL</label>
              <input id="videoUrl" name="videoUrl" placeholder="https://youtu.be/..." [(ngModel)]="videoForm.videoUrl" required>
            </div>

            <div class="meta-grid">
              <div class="field">
                <label for="videoDuration">Duration (Minutes)</label>
                <input id="videoDuration" name="videoDuration" type="number" min="1" [(ngModel)]="videoForm.durationMinutes" required>
              </div>

              <div class="field">
                <label for="videoOrder">Order</label>
                <input id="videoOrder" name="videoOrder" type="number" min="1" [(ngModel)]="videoForm.sortOrder" required>
              </div>

              <div class="field">
                <label for="videoMandatory">Requirement</label>
                <select id="videoMandatory" name="videoMandatory" [(ngModel)]="videoForm.mandatory">
                  <option [ngValue]="true">Mandatory</option>
                  <option [ngValue]="false">Optional</option>
                </select>
              </div>
            </div>

            <button class="btn" type="submit">Add Video</button>
          </form>
        } @else {
          <form class="content-form compact-form-card" (ngSubmit)="addMaterial()">
            <div class="field">
              <label for="materialTitle">Material Title</label>
              <input id="materialTitle" name="materialTitle" placeholder="Lesson slide / reading material" [(ngModel)]="materialForm.title" required>
            </div>

            <div class="field">
              <label for="materialType">Material Type</label>
              <select id="materialType" name="materialType" [(ngModel)]="materialForm.materialType">
                <option value="PDF">PDF</option>
                <option value="SLIDE">SLIDE</option>
                <option value="REFERENCE">REFERENCE</option>
                <option value="LINK">LINK</option>
              </select>
            </div>

            <div class="field">
              <label for="materialUrl">Resource URL</label>
              <input id="materialUrl" name="materialUrl" placeholder="https://..." [(ngModel)]="materialForm.resourceUrl" required>
            </div>

            <button class="btn" type="submit">Add Material</button>
          </form>
        }
      }

      <div class="content-list-wrap">
        <h3>Lessons / Resources</h3>
        @if (orderedContentItems.length === 0) {
          <p class="muted">No content yet for this course.</p>
        } @else {
          <ul class="content-list">
            @for (item of orderedContentItems; track contentKey(item)) {
              <li class="content-row" [class.active]="isSelectedItem(item)">
                <button type="button" class="item-main" (click)="selectContentItem(item)">
                  <span class="item-tag">{{ item.itemType === "VIDEO" ? "VIDEO" : (item.materialType ?? "MATERIAL") }}</span>
                  <span class="item-title">{{ item.title }}</span>
                  <span class="item-meta">{{ itemSubtitle(item) }}</span>
                </button>

                <div class="row-actions">
                  <button type="button" class="menu-btn" (click)="selectContentItem(item); $event.stopPropagation()">Edit</button>
                  <button type="button" class="menu-btn more-btn" (click)="toggleActions(item, $event)" aria-label="More actions">&#8942;</button>

                  @if (actionMenuKey === contentKey(item)) {
                    <div class="action-menu" (click)="$event.stopPropagation()">
                      <button type="button" (click)="selectContentItem(item); actionMenuKey = null;">Edit settings</button>
                      @if (item.itemType === "VIDEO") {
                        <button type="button" [disabled]="!canMoveVideo(item, -1)" (click)="moveVideo(item, -1)">Move up</button>
                        <button type="button" [disabled]="!canMoveVideo(item, 1)" (click)="moveVideo(item, 1)">Move down</button>
                      }
                      <button type="button" (click)="duplicateItem(item)">Duplicate</button>
                      <button type="button" class="danger" (click)="deleteItem(item)">Delete</button>
                    </div>
                  }
                </div>
              </li>
            }
          </ul>
        }
      </div>
      </aside>

      <section class="panel settings-panel">
      @if (selectedContentItem) {
        <p class="crumbs">
          Courses &rsaquo; {{ currentCourse?.title ?? "Course" }} &rsaquo; {{ selectedContentItem.title }} &rsaquo; Edit settings
        </p>
        <h2>Updating {{ selectedContentItem.itemType === "VIDEO" ? "Lesson Video" : "Learning Material" }}</h2>

        @if (selectedContentItem.itemType === "VIDEO") {
          <form class="edit-form" (ngSubmit)="saveSelectedItem()">
            <div class="form-sections-menu">
              @for (section of settingsSections; track section.key) {
                <button class="section-trigger" type="button" (click)="toggleSettingsSection(section.key)">
                  <span class="section-icon">
                    @if (isSettingsSectionOpen(section.key)) { &#9662; } @else { &#9656; }
                  </span>
                  <span>{{ section.label }}</span>
                </button>
              }
            </div>

            @if (isSettingsSectionOpen("COURSE_CONTENT")) {
              <div class="form-section-block">
                <div class="field">
                  <label for="editVideoTitle">Name</label>
                  <input id="editVideoTitle" name="editVideoTitle" [(ngModel)]="editVideoForm.title" required>
                </div>

                <div class="field">
                  <label for="editVideoDescription">Description</label>
                  <textarea id="editVideoDescription" name="editVideoDescription" rows="4" [(ngModel)]="editVideoForm.description" required></textarea>
                </div>
              </div>
            }

            @if (isSettingsSectionOpen("LEARNING_RESOURCES")) {
              <div class="form-section-block">
                <div class="field">
                  <label for="editVideoUrl">Page Content URL</label>
                  <input id="editVideoUrl" name="editVideoUrl" [(ngModel)]="editVideoForm.videoUrl" required>
                </div>
              </div>
            }

            @if (isSettingsSectionOpen("UPDATING_VIDEO")) {
              <div class="form-section-block">
                <div class="meta-grid">
                  <div class="field">
                    <label for="editVideoDuration">Duration (Minutes)</label>
                    <input id="editVideoDuration" name="editVideoDuration" type="number" min="1" [(ngModel)]="editVideoForm.durationMinutes" required>
                  </div>
                  <div class="field">
                    <label for="editVideoOrder">Order</label>
                    <input id="editVideoOrder" name="editVideoOrder" type="number" min="1" [(ngModel)]="editVideoForm.sortOrder" required>
                  </div>
                  <div class="field">
                    <label for="editVideoMandatory">Requirement</label>
                    <select id="editVideoMandatory" name="editVideoMandatory" [(ngModel)]="editVideoForm.mandatory">
                      <option [ngValue]="true">Mandatory</option>
                      <option [ngValue]="false">Optional</option>
                    </select>
                  </div>
                </div>
              </div>
            }

            <div class="edit-actions">
              <button class="btn" type="submit">Save Changes</button>
              <button class="btn btn-outline" type="button" (click)="openLink(editVideoForm.videoUrl)">Open Link</button>
            </div>
          </form>
        } @else {
          <form class="edit-form" (ngSubmit)="saveSelectedItem()">
            <div class="form-sections-menu">
              @for (section of settingsSections; track section.key) {
                <button class="section-trigger" type="button" (click)="toggleSettingsSection(section.key)">
                  <span class="section-icon">
                    @if (isSettingsSectionOpen(section.key)) { &#9662; } @else { &#9656; }
                  </span>
                  <span>{{ section.label }}</span>
                </button>
              }
            </div>

            @if (isSettingsSectionOpen("COURSE_CONTENT")) {
              <div class="form-section-block">
                <div class="field">
                  <label for="editMaterialTitle">Name</label>
                  <input id="editMaterialTitle" name="editMaterialTitle" [(ngModel)]="editMaterialForm.title" required>
                </div>

                <div class="field">
                  <label for="editMaterialType">Material Type</label>
                  <select id="editMaterialType" name="editMaterialType" [(ngModel)]="editMaterialForm.materialType">
                    <option value="PDF">PDF</option>
                    <option value="SLIDE">SLIDE</option>
                    <option value="REFERENCE">REFERENCE</option>
                    <option value="LINK">LINK</option>
                  </select>
                </div>
              </div>
            }

            @if (isSettingsSectionOpen("LEARNING_RESOURCES")) {
              <div class="form-section-block">
                <div class="field">
                  <label for="editMaterialUrl">Resource URL</label>
                  <input id="editMaterialUrl" name="editMaterialUrl" [(ngModel)]="editMaterialForm.resourceUrl" required>
                </div>
              </div>
            }

            @if (isSettingsSectionOpen("UPDATING_VIDEO")) {
              <div class="form-section-block section-empty">
                <p class="muted">Updating Video section is not applicable for learning materials.</p>
              </div>
            }

            <div class="edit-actions">
              <button class="btn" type="submit">Save Changes</button>
              <button class="btn btn-outline" type="button" (click)="openLink(editMaterialForm.resourceUrl)">Open Link</button>
            </div>
          </form>
        }
      } @else {
        <div class="empty-edit">
          <h2>Select an item to edit</h2>
          <p class="muted">Click any lesson or material from the left panel.</p>
        </div>
      }
      </section>
    </section>
  }

</div>
